### 5. Idempotency Properties

```rust
proptest! {
    /// Property: Parsing is idempotent (multiple parses give same result)
    #[test]
    fn parse_idempotent(
        bytes in prop::collection::vec(any::<u8>(), 0..100)
    ) {
        let result1 = KeyParser::parse(&bytes);
        let result2 = KeyParser::parse(&bytes);
        let result3 = KeyParser::parse(&bytes);

        prop_assert_eq!(result1, result2);
        prop_assert_eq!(result2, result3);
    }

    /// Property: Serialization is idempotent
    #[test]
    fn serialize_idempotent(
        key in arb_serializable_key()
    ) {
        let bytes1 = KeySerializer::serialize(&key);
        let bytes2 = KeySerializer::serialize(&key);
        let bytes3 = KeySerializer::serialize(&key);

        prop_assert_eq!(bytes1, bytes2);
        prop_assert_eq!(bytes2, bytes3);
    }

    /// Property: Double roundtrip equals single roundtrip
    #[test]
    fn double_roundtrip_stable(
        key in arb_serializable_key()
    ) {
        // First roundtrip
        let bytes1 = KeySerializer::serialize(&key);
        let (key1, _) = KeyParser::parse(&bytes1).unwrap();

        // Second roundtrip
        let bytes2 = KeySerializer::serialize(&key1);
        let (key2, _) = KeyParser::parse(&bytes2).unwrap();

        // Third roundtrip
        let bytes3 = KeySerializer::serialize(&key2);
        let (key3, _) = KeyParser::parse(&bytes3).unwrap();

        // All should be equal
        prop_assert_eq!(key1, key2);
        prop_assert_eq!(key2, key3);
        prop_assert_eq!(bytes2, bytes3, "Serialization should stabilize");
    }
}
